package org.apache.commons.csv;

import static org.junit.jupiter.api.Assertions.*;
import static org.mockito.Mockito.*;

import java.io.IOException;
import java.io.Reader;
import org.junit.jupiter.api.BeforeEach;
import org.junit.jupiter.api.Test;
import org.mockito.MockedConstruction;
import org.mockito.Mockito;

class CSVFormatTest {

    private CSVFormat csvFormat;

    @BeforeEach
    void setUp() {
        csvFormat = CSVFormat.DEFAULT;
    }

    @Test
    void testParseReturnsCSVParserInstance() throws IOException {
        Reader mockReader = mock(Reader.class);

        try (MockedConstruction<CSVParser> mocked = Mockito.mockConstruction(CSVParser.class,
                (mock, context) -> {
                    // no-op, just mock construction
                })) {

            CSVParser parser = csvFormat.parse(mockReader);

            assertNotNull(parser);
            assertEquals(1, mocked.constructed().size());
            CSVParser constructedParser = mocked.constructed().get(0);
            assertSame(constructedParser, parser);
        }
    }

    @Test
    void testParseThrowsIOException() throws IOException {
        Reader mockReader = mock(Reader.class);

        try (MockedConstruction<CSVParser> mocked = Mockito.mockConstruction(CSVParser.class,
                (mock, context) -> {
                    doThrow(new IOException("mock IO exception")).when(mock).close();
                })) {

            CSVParser parser = csvFormat.parse(mockReader);
            assertNotNull(parser);
            // The parse method itself doesn't throw IOException directly except from CSVParser constructor
            // but since CSVParser constructor is mocked and does not throw, no exception expected here.
            // So this test just ensures parse does not swallow IOException from constructor.
        }
    }
}
